import React from "react";
 const WeatherCard =({city,icon,temperature,wind,humidity})=>{
    return(
        <div>
            <h1>City</h1>
            <h2>Temperature</h2>
            <h3>Wind</h3>
            <img src={icon} alt="Weather Icon" width="120"/>
        </div>

    )
 };
 export default WeatherCard;
